contracts/Faucet.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

contract Faucet is Ownable {
    uint256 public constant NATIVE_AMOUNT = 0.1 ether;
    uint256 public constant TOKEN_AMOUNT = 1000 * 10**18; // 1000 tokens
    uint256 public constant COOLDOWN_TIME = 24 hours;

    mapping(address => uint256) public lastRequestTime;
    mapping(address => bool) public tokenWhitelist;

    event NativeTokensRequested(address indexed user, uint256 amount);
    event TokensRequested(address indexed user, address indexed token, uint256 amount);
    event TokenWhitelisted(address indexed token, bool status);

    constructor() Ownable(msg.sender) {}

    receive() external payable {}

    function requestNativeTokens() external {
        require(
            block.timestamp >= lastRequestTime[msg.sender] + COOLDOWN_TIME,
            "Please wait 24 hours between requests"
        );
        require(address(this).balance >= NATIVE_AMOUNT, "Faucet is empty");

        lastRequestTime[msg.sender] = block.timestamp;

        (bool success, ) = msg.sender.call{value: NATIVE_AMOUNT}("");
        require(success, "Transfer failed");

        emit NativeTokensRequested(msg.sender, NATIVE_AMOUNT);
    }

    function requestTokens(address token, uint256 amount) external {
        require(
            block.timestamp >= lastRequestTime[msg.sender] + COOLDOWN_TIME,
            "Please wait 24 hours between requests"
        );
        require(tokenWhitelist[token], "Token not whitelisted");
        require(amount <= TOKEN_AMOUNT, "Amount exceeds limit");

        lastRequestTime[msg.sender] = block.timestamp;

        // Try to mint tokens if the token supports it
        (bool success, ) = token.call(
            abi.encodeWithSignature("faucetMint(address,uint256)", msg.sender, amount)
        );

        if (!success) {
            // If minting fails, try regular transfer
            IERC20 tokenContract = IERC20(token);
            require(
                tokenContract.balanceOf(address(this)) >= amount,
                "Insufficient token balance"
            );
            require(tokenContract.transfer(msg.sender, amount), "Transfer failed");
        }

        emit TokensRequested(msg.sender, token, amount);
    }

    function whitelistToken(address token, bool status) external onlyOwner {
        tokenWhitelist[token] = status;
        emit TokenWhitelisted(token, status);
    }

    function withdraw() external onlyOwner {
        (bool success, ) = owner().call{value: address(this).balance}("");
        require(success, "Withdrawal failed");
    }

    function withdrawToken(address token) external onlyOwner {
        IERC20 tokenContract = IERC20(token);
        uint256 balance = tokenContract.balanceOf(address(this));
        require(tokenContract.transfer(owner(), balance), "Token withdrawal failed");
    }

    function getCooldownTime(address user) external view returns (uint256) {
        if (lastRequestTime[user] + COOLDOWN_TIME > block.timestamp) {
            return (lastRequestTime[user] + COOLDOWN_TIME) - block.timestamp;
        }
        return 0;
    }
}

contracts/SimpleSwap.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract SimpleSwap is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    uint256 public constant FEE_PERCENT = 3; // 0.3% fee
    uint256 public constant FEE_DENOMINATOR = 1000;

    struct Pool {
        uint256 reserve0;
        uint256 reserve1;
        uint256 totalLiquidity;
    }

    mapping(address => mapping(address => Pool)) public pools;
    mapping(address => mapping(address => mapping(address => uint256))) public liquidity;

    event Swap(
        address indexed user,
        address indexed tokenIn,
        address indexed tokenOut,
        uint256 amountIn,
        uint256 amountOut
    );

    event LiquidityAdded(
        address indexed provider,
        address indexed token0,
        address indexed token1,
        uint256 amount0,
        uint256 amount1,
        uint256 liquidity
    );

    event LiquidityRemoved(
        address indexed provider,
        address indexed token0,
        address indexed token1,
        uint256 amount0,
        uint256 amount1,
        uint256 liquidity
    );

    constructor() Ownable(msg.sender) {}

    function addLiquidity(
        address token0,
        address token1,
        uint256 amount0,
        uint256 amount1
    ) external nonReentrant returns (uint256 liquidityMinted) {
        require(token0 != token1, "Identical tokens");
        require(amount0 > 0 && amount1 > 0, "Invalid amounts");

        (address tokenA, address tokenB) = token0 < token1 ? (token0, token1) : (token1, token0);
        (uint256 amountA, uint256 amountB) = token0 < token1 ? (amount0, amount1) : (amount1, amount0);

        IERC20(tokenA).safeTransferFrom(msg.sender, address(this), amountA);
        IERC20(tokenB).safeTransferFrom(msg.sender, address(this), amountB);

        Pool storage pool = pools[tokenA][tokenB];

        if (pool.totalLiquidity == 0) {
            liquidityMinted = sqrt(amountA * amountB);
            pool.reserve0 = amountA;
            pool.reserve1 = amountB;
        } else {
            uint256 liquidity0 = (amountA * pool.totalLiquidity) / pool.reserve0;
            uint256 liquidity1 = (amountB * pool.totalLiquidity) / pool.reserve1;
            liquidityMinted = liquidity0 < liquidity1 ? liquidity0 : liquidity1;

            pool.reserve0 += amountA;
            pool.reserve1 += amountB;
        }

        pool.totalLiquidity += liquidityMinted;
        liquidity[msg.sender][tokenA][tokenB] += liquidityMinted;

        emit LiquidityAdded(msg.sender, tokenA, tokenB, amountA, amountB, liquidityMinted);
    }

    function removeLiquidity(
        address token0,
        address token1,
        uint256 liquidityAmount
    ) external nonReentrant returns (uint256 amount0, uint256 amount1) {
        (address tokenA, address tokenB) = token0 < token1 ? (token0, token1) : (token1, token0);

        require(liquidity[msg.sender][tokenA][tokenB] >= liquidityAmount, "Insufficient liquidity");

        Pool storage pool = pools[tokenA][tokenB];

        amount0 = (liquidityAmount * pool.reserve0) / pool.totalLiquidity;
        amount1 = (liquidityAmount * pool.reserve1) / pool.totalLiquidity;

        pool.reserve0 -= amount0;
        pool.reserve1 -= amount1;
        pool.totalLiquidity -= liquidityAmount;
        liquidity[msg.sender][tokenA][tokenB] -= liquidityAmount;

        IERC20(tokenA).safeTransfer(msg.sender, amount0);
        IERC20(tokenB).safeTransfer(msg.sender, amount1);

        (amount0, amount1) = token0 < token1 ? (amount0, amount1) : (amount1, amount0);

        emit LiquidityRemoved(msg.sender, token0, token1, amount0, amount1, liquidityAmount);
    }

    function swap(
        address tokenIn,
        address tokenOut,
        uint256 amountIn,
        uint256 minAmountOut
    ) external nonReentrant returns (uint256 amountOut) {
        require(tokenIn != tokenOut, "Same token");
        require(amountIn > 0, "Invalid amount");

        (address token0, address token1) = tokenIn < tokenOut ? (tokenIn, tokenOut) : (tokenOut, tokenIn);
        Pool storage pool = pools[token0][token1];

        require(pool.totalLiquidity > 0, "Pool does not exist");

        IERC20(tokenIn).safeTransferFrom(msg.sender, address(this), amountIn);

        uint256 amountInWithFee = (amountIn * (FEE_DENOMINATOR - FEE_PERCENT)) / FEE_DENOMINATOR;

        if (tokenIn == token0) {
            amountOut = (amountInWithFee * pool.reserve1) / (pool.reserve0 + amountInWithFee);
            pool.reserve0 += amountIn;
            pool.reserve1 -= amountOut;
        } else {
            amountOut = (amountInWithFee * pool.reserve0) / (pool.reserve1 + amountInWithFee);
            pool.reserve1 += amountIn;
            pool.reserve0 -= amountOut;
        }

        require(amountOut >= minAmountOut, "Insufficient output amount");

        IERC20(tokenOut).safeTransfer(msg.sender, amountOut);

        emit Swap(msg.sender, tokenIn, tokenOut, amountIn, amountOut);
    }

    function getAmountOut(
        address tokenIn,
        address tokenOut,
        uint256 amountIn
    ) external view returns (uint256) {
        (address token0, address token1) = tokenIn < tokenOut ? (tokenIn, tokenOut) : (tokenOut, tokenIn);
        Pool memory pool = pools[token0][token1];

        if (pool.totalLiquidity == 0) return 0;

        uint256 amountInWithFee = (amountIn * (FEE_DENOMINATOR - FEE_PERCENT)) / FEE_DENOMINATOR;

        if (tokenIn == token0) {
            return (amountInWithFee * pool.reserve1) / (pool.reserve0 + amountInWithFee);
        } else {
            return (amountInWithFee * pool.reserve0) / (pool.reserve1 + amountInWithFee);
        }
    }

    function getPoolInfo(address token0, address token1) external view returns (
        uint256 reserve0,
        uint256 reserve1,
        uint256 totalLiquidity
    ) {
        (address tokenA, address tokenB) = token0 < token1 ? (token0, token1) : (token1, token0);
        Pool memory pool = pools[tokenA][tokenB];

        if (token0 == tokenA) {
            return (pool.reserve0, pool.reserve1, pool.totalLiquidity);
        } else {
            return (pool.reserve1, pool.reserve0, pool.totalLiquidity);
        }
    }

    function sqrt(uint256 y) internal pure returns (uint256 z) {
        if (y > 3) {
            z = y;
            uint256 x = y / 2 + 1;
            while (x < z) {
                z = x;
                x = (y / x + x) / 2;
            }
        } else if (y != 0) {
            z = 1;
        }
    }
}

contracts/Staking.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

contract Staking is Ownable, ReentrancyGuard {
    using SafeERC20 for IERC20;

    IERC20 public stakingToken;

    uint256 public rewardRate = 100; // 100 basis points = 1% per period
    uint256 public constant REWARD_DENOMINATOR = 10000;
    uint256 public constant REWARD_PERIOD = 1 days;

    struct StakeInfo {
        uint256 amount;
        uint256 startTime;
        uint256 lastClaimTime;
    }

    mapping(address => StakeInfo) public stakes;
    uint256 public totalStaked;

    event Staked(address indexed user, uint256 amount);
    event Unstaked(address indexed user, uint256 amount);
    event RewardsClaimed(address indexed user, uint256 reward);
    event RewardRateUpdated(uint256 newRate);

    constructor(address _stakingToken) Ownable(msg.sender) {
        require(_stakingToken != address(0), "Invalid token address");
        stakingToken = IERC20(_stakingToken);
    }

    function stake(uint256 amount) external nonReentrant {
        require(amount > 0, "Cannot stake 0");

        // Claim pending rewards if any
        if (stakes[msg.sender].amount > 0) {
            _claimRewards(msg.sender);
        }

        stakingToken.safeTransferFrom(msg.sender, address(this), amount);

        stakes[msg.sender].amount += amount;
        stakes[msg.sender].startTime = block.timestamp;
        stakes[msg.sender].lastClaimTime = block.timestamp;
        totalStaked += amount;

        emit Staked(msg.sender, amount);
    }

    function unstake(uint256 amount) external nonReentrant {
        require(amount > 0, "Cannot unstake 0");
        require(stakes[msg.sender].amount >= amount, "Insufficient staked amount");

        // Claim pending rewards
        _claimRewards(msg.sender);

        stakes[msg.sender].amount -= amount;
        totalStaked -= amount;

        if (stakes[msg.sender].amount == 0) {
            delete stakes[msg.sender];
        }

        stakingToken.safeTransfer(msg.sender, amount);

        emit Unstaked(msg.sender, amount);
    }

    function claimRewards() external nonReentrant {
        require(stakes[msg.sender].amount > 0, "No staked amount");
        _claimRewards(msg.sender);
    }

    function _claimRewards(address user) internal {
        uint256 reward = pendingRewards(user);
        if (reward > 0) {
            stakes[user].lastClaimTime = block.timestamp;

            // Mint rewards to user (requires stakingToken to have mint function)
            // For testnet, we'll use the faucetMint function
            (bool success, ) = address(stakingToken).call(
                abi.encodeWithSignature("faucetMint(address,uint256)", user, reward)
            );

            if (!success) {
                // If minting fails, transfer from contract balance
                uint256 contractBalance = stakingToken.balanceOf(address(this));
                uint256 availableRewards = contractBalance > totalStaked ? contractBalance - totalStaked : 0;

                if (availableRewards >= reward) {
                    stakingToken.safeTransfer(user, reward);
                } else if (availableRewards > 0) {
                    stakingToken.safeTransfer(user, availableRewards);
                    reward = availableRewards;
                } else {
                    reward = 0;
                }
            }

            if (reward > 0) {
                emit RewardsClaimed(user, reward);
            }
        }
    }

    function pendingRewards(address user) public view returns (uint256) {
        StakeInfo memory stakeInfo = stakes[user];
        if (stakeInfo.amount == 0) {
            return 0;
        }

        uint256 timeDiff = block.timestamp - stakeInfo.lastClaimTime;
        uint256 periods = timeDiff / REWARD_PERIOD;

        if (periods == 0) {
            return 0;
        }

        return (stakeInfo.amount * rewardRate * periods) / REWARD_DENOMINATOR;
    }

    function balanceOf(address account) external view returns (uint256) {
        return stakes[account].amount;
    }

    function setRewardRate(uint256 newRate) external onlyOwner {
        require(newRate <= 1000, "Rate too high"); // Max 10% per period
        rewardRate = newRate;
        emit RewardRateUpdated(newRate);
    }

    function depositRewards(uint256 amount) external onlyOwner {
        stakingToken.safeTransferFrom(msg.sender, address(this), amount);
    }

    function emergencyWithdraw() external onlyOwner {
        uint256 contractBalance = stakingToken.balanceOf(address(this));
        uint256 availableRewards = contractBalance > totalStaked ? contractBalance - totalStaked : 0;

        if (availableRewards > 0) {
            stakingToken.safeTransfer(owner(), availableRewards);
        }
    }

    function getStakeInfo(address user) external view returns (
        uint256 amount,
        uint256 startTime,
        uint256 lastClaimTime,
        uint256 pending
    ) {
        StakeInfo memory info = stakes[user];
        return (info.amount, info.startTime, info.lastClaimTime, pendingRewards(user));
    }
}

